async function run(input) {
  var text = String((input && input.text) || '');
  var zeichen = text.length;
  var zeichenOhneLeer = text.replace(/\s/g, '').length;
  var woerterArr = text.split(/\s+/).filter(function (w) { return w.length > 0; });
  var woerter = woerterArr.length;
  var saetzeArr = text.split(/[.!?]+/).filter(function (s) { return s.trim().length > 0; });
  var saetze = saetzeArr.length;
  var absaetzeArr = text.split(/\n\s*\n/).filter(function (p) { return p.trim().length > 0; });
  var absaetze = absaetzeArr.length;
  var lesezeitMinuten = woerter > 0 ? Math.ceil(woerter / 200) : 0;
  var letterCount = woerterArr.reduce(function (sum, w) { return sum + w.replace(/[^\p{L}\p{N}]/gu, '').length; }, 0);
  var durchschnWortlaenge = woerter > 0 ? Math.round((letterCount / woerter) * 100) / 100 : 0;
  return {
    zeichen: zeichen,
    zeichenOhneLeer: zeichenOhneLeer,
    woerter: woerter,
    saetze: saetze,
    absaetze: absaetze,
    lesezeitMinuten: lesezeitMinuten,
    durchschnWortlaenge: durchschnWortlaenge
  };
}
